 280→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
 281→  const monthlyProjectCount = useMemo(() => {
 282→    if (history.length === 0) return 0;
 283→
 284→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
 285→    const now = new Date();
 286→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
 287→
 288→    // 1. Identifier la date de création (première analyse) de chaque domaine
 289→    const projectCreationDates = new Map<string, Date>();
 290→    
 291→    history.forEach(h => {
 292→        let hostname;
 293→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
 294→        
 295→        const analysisDate = new Date(h.timestamp);
 296→        
 297→        if (!projectCreationDates.has(hostname)) {
 298→            projectCreationDates.set(hostname, analysisDate);
 299→        } else {
 300→            // On garde la date la plus ancienne trouvée pour ce domaine
 301→            if (analysisDate < projectCreationDates.get(hostname)!) {
 302→                projectCreationDates.set(hostname, analysisDate);
 303→            }
 304→        }
 305→    });
 306→
 307→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
 308→    let count = 0;
 309→    projectCreationDates.forEach((creationDate) => {
 310→        if (creationDate >= billingCycleStart) {
