 368→  const handleAnalyze = async (url: string) => {
 369→    // Vérification de la limite de projets (Quota mensuel)
 370→    if (user) {
 371→        const limit = PLAN_LIMITS[user.plan] || 1;
 372→        let hostname = url;
 373→        try { hostname = new URL(url).hostname; } catch(e) {}
 374→
 375→        // On vérifie si c'est un projet déjà existant dans l'historique global
 376→        const isExistingProject = history.some(h => {
 377→            try { return new URL(h.url).hostname === hostname; } 
 378→            catch(e) { return false; }
 379→        });
 380→
 381→        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
 382→        // Les anciens projets ne comptent pas dans cette limite
 383→        if (!isExistingProject && monthlyProjectCount >= limit) {
