  72→// Animated number hook for smooth credit transitions
  73→const useAnimatedNumber = (value: number, duration = 600) => {
  74→  const [display, setDisplay] = useState(value);
  75→  const prevValue = useRef(value);
  76→  useEffect(() => {
  77→    if (prevValue.current === value) return;
  78→    const start = prevValue.current;
  79→    const diff = value - start;
  80→    const startTime = performance.now();
  81→    const animate = (now: number) => {
  82→      const progress = Math.min((now - startTime) / duration, 1);
  83→      const eased = 1 - Math.pow(1 - progress, 3);
  84→      setDisplay(Math.round(start + diff * eased));
  85→      if (progress < 1) requestAnimationFrame(animate);
  86→    };
  87→    requestAnimationFrame(animate);
  88→    prevValue.current = value;
  89→  }, [value, duration]);
  90→  return display;
  91→};
