 492→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
 493→    const timestamp = new Date().toISOString();
 494→    const solutionWithMeta = { ...solution, timestamp };
 495→
 496→    setAnalysisData(prev => {
 497→        if (!prev || prev.timestamp !== analysisId) return prev;
 498→        
 499→        return {
 500→            ...prev,
 501→            generatedSolutions: {
 502→                ...(prev.generatedSolutions || {}),
 503→                [recommendationId]: solutionWithMeta
 504→            }
 505→        };
 506→    });
 507→
 508→    // We need to find the index in the history to update the DB
 509→    setHistory(prevHistory => {
 510→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
 511→        if (index !== -1) {
 512→            const updatedItem = {
 513→                ...prevHistory[index],
 514→                generatedSolutions: {
 515→                    ...(prevHistory[index].generatedSolutions || {}),
 516→                    [recommendationId]: solutionWithMeta
 517→                }
 518→            };
 519→            // Persist using db service
 520→            const newHistory = [...prevHistory];
 521→            newHistory[index] = updatedItem;
 522→            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
 523→            db.update(index, updatedItem);
 524→            return newHistory;
 525→        }
 526→        return prevHistory;
 527→    });
 528→  }, []); 
