import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { AnalysisResult, Recommendation, GeneratedSolution, User } from '../types';
import { generateSolution } from '../services/generator';
import RecommendationCard from '../components/RecommendationCard';
import GenerationModal from '../components/GenerationModal';
import ScoreRing from '../components/ScoreRing';
import EngineBreakdown from '../components/EngineBreakdown';
import { mapAnalysisResults, CRITERIA_LABELS } from '../lib/criteria-mapper';
import { calculateEngineScores, calculateProjectedScores, getMostImpactedEngines } from '../lib/engine-score-calculator';
import { ENGINE_PROFILES } from '../config/engine-weights';
import { Zap, AlertTriangle, Fuel, ArrowRight, ArrowUp, CheckSquare, Square, TrendingUp, Lock, Package } from 'lucide-react';

// Vault system — Generate All, Reveal on Credit
import { getContentBlocks, getVaultSummary, unlockContent, unlockAll, hasVault } from '../services/solution-vault';
import type { ContentBlock, VaultSummary } from '../services/solution-vault';
import LockedContentCard from '../components/LockedContentCard';
import UnlockAllBanner from '../components/UnlockAllBanner';

interface Props {
  data: AnalysisResult;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
  onNavigateToAnalysis: () => void;
  onNavigateToRecharge: () => void;
}

const ActionPlan: React.FC<Props> = ({ data, user, onDeductCredits, onSaveSolution, onNavigateToAnalysis, onNavigateToRecharge }) => {
  // Generation Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isGeneratingSolution, setIsGeneratingSolution] = useState(false);
  const [generatedSolution, setGeneratedSolution] = useState<GeneratedSolution | null>(null);

  // Checked recommendations for projected score
  const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

  // ═══ VAULT — Système "Generate All, Reveal on Credit" ═══
  const auditId = data?.timestamp || 'current';
  const [vaultBlocks, setVaultBlocks] = useState<ContentBlock[]>([]);
  const [vaultSummary, setVaultSummary] = useState<VaultSummary | null>(null);
  const [vaultReloadKey, setVaultReloadKey] = useState(0);

  // Charger les blocs depuis le vault
  useEffect(() => {
    if (!data) return;
    const loadedBlocks = getContentBlocks(auditId);
    setVaultBlocks(loadedBlocks);
    if (loadedBlocks.length > 0) {
      setVaultSummary(getVaultSummary(auditId));
    }
  }, [auditId, data, vaultReloadKey]);

  // Gérer le déblocage d'un bloc individuel
  const handleUnlockBlock = useCallback((blockId: string) => {
    const success = onDeductCredits(1);
    if (!success) return;
    unlockContent(auditId, blockId);
    setVaultReloadKey(prev => prev + 1);
  }, [auditId, onDeductCredits]);

