 282→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
 283→  const monthlyProjectCount = useMemo(() => {
 284→    if (history.length === 0) return 0;
 285→
 286→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
 287→    const now = new Date();
 288→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
 289→
 290→    // 1. Identifier la date de création (première analyse) de chaque domaine
 291→    const projectCreationDates = new Map<string, Date>();
 292→    
 293→    history.forEach(h => {
 294→        let hostname;
 295→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
 296→        
 297→        const analysisDate = new Date(h.timestamp);
 298→        
 299→        if (!projectCreationDates.has(hostname)) {
 300→            projectCreationDates.set(hostname, analysisDate);
 301→        } else {
 302→            // On garde la date la plus ancienne trouvée pour ce domaine
 303→            if (analysisDate < projectCreationDates.get(hostname)!) {
 304→                projectCreationDates.set(hostname, analysisDate);
 305→            }
 306→        }
 307→    });
 308→
 309→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
 310→    let count = 0;
 311→    projectCreationDates.forEach((creationDate) => {
 312→        if (creationDate >= billingCycleStart) {
 313→            count++;
 314→        }
 315→    });
 316→    
 317→    return count;
 318→  }, [history]);
