 67→        try {
 68→            const host = new URL(item.url).hostname;
 69→            if (!uniqueMap.has(host) || new Date(item.timestamp) > new Date(uniqueMap.get(host)!.timestamp)) {
 70→                uniqueMap.set(host, item);
 71→            }
 72→        } catch(e) {}
 73→      });
 74→      return Array.from(uniqueMap.values()).map((analysis, index) => mapAnalysisToProject(analysis, index));
 75→    } else {
