            <p className="text-xs text-gray-500">{queries.length} requêtes configurées</p>
          </div>
        </button>

        <button
          onClick={() => onNavigate('benchmark')}
          className="ninja-card p-5 rounded-2xl border border-white/[0.08] hover:border-yellow-500/30 transition-all flex items-center gap-4 group"
        >
          <div className="w-10 h-10 rounded-full bg-yellow-500/20 flex items-center justify-center text-yellow-400 group-hover:scale-110 transition-transform">
            <Trophy size={18} />
          </div>
          <div className="text-left">
