    const timestamp = new Date().toISOString();
    const solutionWithMeta = { ...solution, timestamp };

    setAnalysisData(prev => {
        if (!prev || prev.timestamp !== analysisId) return prev;

        return {
            ...prev,
            generatedSolutions: {
                ...(prev.generatedSolutions || {}),
                [recommendationId]: solutionWithMeta
            }
        };
    });

    // We need to find the index in the history to update the DB
    setHistory(prevHistory => {
        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
        if (index !== -1) {
            const updatedItem = {
                ...prevHistory[index],
                generatedSolutions: {
                    ...(prevHistory[index].generatedSolutions || {}),
                    [recommendationId]: solutionWithMeta
                }
            };
            // Persist using db service
            const newHistory = [...prevHistory];
            newHistory[index] = updatedItem;
            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
            db.update(index, updatedItem);
            return newHistory;
        }
        return prevHistory;
