              onBack={goBack}
              user={user}
            />
          )}
          {currentView === 'citation-detail' && (
            <CitationDetailPage
              key={`citation-detail-${refreshKey}`}
              onBack={goBack}
              user={user}
            />
          )}
          {currentView === 'benchmark' && (
            <BenchmarkPage
              key={`benchmark-${refreshKey}`}
