import React, { useMemo, useState } from 'react';
import { AnalysisResult, CategoryScore, GeneratedSolution, User } from '../types';
import CategoryCard from '../components/CategoryCard';
import EngineBreakdown from '../components/EngineBreakdown';
import { calculateEngineScores } from '../lib/engine-score-calculator';
import { mapAnalysisResults } from '../lib/criteria-mapper';
import { Info, Download, Share2, ScanLine, CheckCircle2, AlertTriangle, XCircle } from 'lucide-react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

interface Props {
  data: AnalysisResult;
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
  initialTab?: 'details' | 'archives' | 'overview'; // Expanded type to include overview
  onNewAnalysis?: () => void;
}

export const Results: React.FC<Props> = ({ data, onBack, user, onDeductCredits, onSaveSolution, onNewAnalysis }) => {
  const [isExporting, setIsExporting] = useState(false);

  const categoryScores = Object.values(data.categories) as CategoryScore[];

  const engineScores = useMemo(() => {
    const criteriaResults = mapAnalysisResults(data);
    return calculateEngineScores(criteriaResults);
  }, [data]);

  const handleDownloadPDF = async () => {
    const element = document.getElementById('full-pdf-report');
    if (!element) return;

    setIsExporting(true);
    try {
      // Wait a moment for the hidden div to render properly
      await new Promise(resolve => setTimeout(resolve, 500));

      const canvas = await html2canvas(element, {
        scale: 2,
        useCORS: true,
        logging: false,
        windowWidth: 1000 // Force width to match container style
      });

      const imgData = canvas.toDataURL('image/jpeg', 0.95);
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
      });

      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();
      const imgWidth = pdfWidth;
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 0;

      // First page
      pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
      heightLeft -= pdfHeight;

      // Subsequent pages if content overflows
      while (heightLeft > 0) {
        position = heightLeft - imgHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
        heightLeft -= pdfHeight;
      }

      const hostname = new URL(data.url).hostname;
      pdf.save(`Audit_AEO_${hostname}_${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (err) {
      console.error('PDF Export failed', err);
      alert('Erreur lors de la génération du PDF.');
    } finally {
      setIsExporting(false);
    }
  };

  const handleShare = async () => {
    const shareData = {
      title: 'Rapport AEO - CitedBy.ai',
      text: `Découvrez l'analyse AEO pour ${data.url} sur CitedBy.ai`,
      url: window.location.href,
    };

