  1→import { GoogleGenAI } from "@google/genai";
  2→import {
  3→  MonitoringResult,
  4→  CitationEntry,
  5→  EngineResult,
  6→  CompetitorData,
  7→  TimeSeriesPoint,
  8→  AIEngine,
  9→  Sentiment,
 10→  SentimentBreakdown,
 11→} from "../types/ai-monitoring";
 12→
 13→const getApiKey = () => {
 14→  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
 15→    return process.env.API_KEY;
 16→  }
 17→  return null;
 18→};
 19→
 20→// ── Deterministic helpers ──
 21→const seededRandom = (seed: number, offset: number): number => {
 22→  const raw = ((seed * 37 + offset * 19 + 11) * 17) % 1000;
 23→  return raw / 1000;
 24→};
 25→
 26→const seededInt = (seed: number, offset: number, min: number, max: number): number => {
 27→  return min + Math.round(seededRandom(seed, offset) * (max - min));
 28→};
 29→
 30→const seededFloat = (seed: number, offset: number, min: number, max: number): number => {
 31→  return Math.round((min + seededRandom(seed, offset) * (max - min)) * 10) / 10;
 32→};
 33→
 34→// ── Fallback deterministic simulation ──
 35→const fallbackSimulation = async (brandName: string, url: string, period: '7d' | '30d' | '90d' = '30d'): Promise<MonitoringResult> => {
 36→  await new Promise(resolve => setTimeout(resolve, 2400));
 37→
 38→  let hostname: string;
 39→  try { hostname = new URL(url).hostname; } catch { hostname = url; }
 40→  const brand = brandName || hostname;
 41→  const seed = brand.length + hostname.length;
 42→
 43→  const periodDays = period === '7d' ? 7 : period === '30d' ? 30 : 90;
 44→  const multiplier = period === '7d' ? 1 : period === '30d' ? 3.5 : 10;
 45→
 46→  // ── Total citations & KPIs ──
 47→  const totalCitations = seededInt(seed, 1, Math.round(12 * multiplier), Math.round(45 * multiplier));
 48→  const shareOfVoice = seededFloat(seed, 2, 8, 42);
 49→  const trend = seededFloat(seed, 3, -15, 25);
 50→
 51→  const overallSentiment: SentimentBreakdown = {
 52→    positive: seededInt(seed, 4, 35, 65),
 53→    neutral: seededInt(seed, 5, 20, 40),
 54→    negative: 0,
 55→  };
 56→  overallSentiment.negative = 100 - overallSentiment.positive - overallSentiment.neutral;
 57→  if (overallSentiment.negative < 0) {
 58→    overallSentiment.neutral += overallSentiment.negative;
 59→    overallSentiment.negative = 0;
 60→  }
 61→
 62→  // ── Engine results ──
 63→  const engines: AIEngine[] = ['ChatGPT', 'Claude', 'Perplexity', 'Gemini', 'AI Overviews'];
 64→  const queryPool = [
 65→    `meilleur ${brand.split('.')[0]} avis`,
 66→    `${brand.split('.')[0]} vs concurrent`,
 67→    `alternative a ${brand.split('.')[0]}`,
 68→    `${brand.split('.')[0]} prix tarif`,
 69→    `${brand.split('.')[0]} fiabilite`,
 70→    `comparatif ${brand.split('.')[0]}`,
 71→    `${brand.split('.')[0]} guide complet`,
 72→    `recommandation ${brand.split('.')[0]}`,
 73→    `${brand.split('.')[0]} pour entreprise`,
 74→    `top solutions ${brand.split('.')[0]}`,
 75→    `${brand.split('.')[0]} expertise`,
 76→    `${brand.split('.')[0]} retour experience`,
 77→  ];
 78→
 79→  const engineResults: EngineResult[] = engines.map((engine, i) => {
 80→    const engineCitations = seededInt(seed, 10 + i, Math.round(3 * multiplier), Math.round(15 * multiplier));
 81→    const engineSov = seededFloat(seed, 20 + i, 5, 45);
 82→    const engineSentiment: SentimentBreakdown = {
 83→      positive: seededInt(seed, 30 + i, 30, 70),
 84→      neutral: seededInt(seed, 40 + i, 15, 40),
 85→      negative: 0,
 86→    };
 87→    engineSentiment.negative = Math.max(0, 100 - engineSentiment.positive - engineSentiment.neutral);
 88→    if (engineSentiment.negative < 0) {
 89→      engineSentiment.neutral += engineSentiment.negative;
 90→      engineSentiment.negative = 0;
 91→    }
 92→
 93→    const topQueries = queryPool
 94→      .sort(() => seededRandom(seed, 50 + i * 10) - 0.5)
 95→      .slice(0, seededInt(seed, 60 + i, 3, 5));
 96→
 97→    return {
 98→      engine,
 99→      totalCitations: engineCitations,
100→      shareOfVoice: engineSov,
101→      avgPosition: seededFloat(seed, 70 + i, 1, 5),
102→      sentiment: engineSentiment,
103→      trend: seededFloat(seed, 80 + i, -20, 30),
104→      topQueries,
105→    };
106→  });
107→
108→  // ── Citations table ──
109→  const sentiments: Sentiment[] = ['positive', 'neutral', 'negative'];
110→  const citationCount = Math.min(totalCitations, 20);
111→  const citations: CitationEntry[] = Array.from({ length: citationCount }, (_, i) => {
112→    const engineIndex = i % 5;
113→    const sentimentIndex = seededInt(seed, 100 + i, 0, 2);
114→    const daysAgo = seededInt(seed, 120 + i, 0, periodDays - 1);
115→    const date = new Date();
116→    date.setDate(date.getDate() - daysAgo);
117→
118→    return {
119→      id: `cit-${seed}-${i}`,
120→      engine: engines[engineIndex],
121→      query: queryPool[i % queryPool.length],
122→      position: seededInt(seed, 140 + i, 1, 8),
123→      date: date.toISOString().split('T')[0],
124→      sentiment: sentiments[sentimentIndex],
125→      snippet: generateSnippet(brand, engines[engineIndex], sentiments[sentimentIndex], seed + i),
126→      confidence: seededInt(seed, 160 + i, 60, 98),
127→    };
128→  }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
129→
130→  // ── Competitors ──
131→  const competitorNames = [
132→    'CompetitorAlpha', 'RivalTech', 'MarketLeader', 'IndustryStar', 'NextGenCorp'
133→  ];
134→  const competitors: CompetitorData[] = competitorNames.slice(0, 4).map((name, i) => ({
135→    name,
136→    totalCitations: seededInt(seed, 200 + i, Math.round(8 * multiplier), Math.round(50 * multiplier)),
137→    shareOfVoice: seededFloat(seed, 210 + i, 5, 35),
138→    avgSentiment: seededInt(seed, 220 + i, 40, 85),
139→    trend: seededFloat(seed, 230 + i, -20, 30),
140→    dominantEngine: engines[seededInt(seed, 240 + i, 0, 4)],
141→  }));
142→
143→  // ── Time series ──
144→  const timeSeries: TimeSeriesPoint[] = Array.from({ length: periodDays }, (_, i) => {
145→    const date = new Date();
146→    date.setDate(date.getDate() - (periodDays - 1 - i));
147→    const daySeed = seed + i * 7;
148→    const chatgpt = seededInt(daySeed, 300, 0, 5);
149→    const claude = seededInt(daySeed, 310, 0, 4);
150→    const perplexity = seededInt(daySeed, 320, 0, 4);
151→    const gemini = seededInt(daySeed, 330, 0, 3);
152→    const aiOverviews = seededInt(daySeed, 340, 0, 4);
153→    return {
154→      date: date.toISOString().split('T')[0],
155→      citations: chatgpt + claude + perplexity + gemini + aiOverviews,
156→      chatgpt,
157→      claude,
158→      perplexity,
159→      gemini,
160→      aiOverviews,
161→    };
162→  });
163→
164→  // ── Summary & recommendations ──
165→  const summary = totalCitations > 80
166→    ? `${brand} beneficie d'une excellente visibilite sur les moteurs IA avec ${totalCitations} citations detectees sur ${periodDays} jours. Le sentiment est majoritairement positif (${overallSentiment.positive}%). La part de voix de ${shareOfVoice}% positionne la marque parmi les leaders cites.`
167→    : totalCitations > 30
168→      ? `${brand} a une visibilite moderee sur les IA generatives avec ${totalCitations} citations sur ${periodDays} jours. Le Share of Voice de ${shareOfVoice}% offre une marge de progression. Concentrez vos efforts sur les moteurs ou la marque est sous-representee.`
169→      : `${brand} a une faible presence dans les reponses IA (${totalCitations} citations sur ${periodDays} jours). La part de voix de ${shareOfVoice}% indique un besoin urgent d'optimisation AEO pour ameliorer la citabilite de la marque.`;
170→
171→  const recommendations = [
172→    'Enrichir le contenu du site avec des donnees factuelles et structurees (Schema.org) pour ameliorer la citabilite.',
173→    'Creer des pages "hub" thematiques qui repondent directement aux questions frequentes detectees.',
174→    'Renforcer les signaux E-E-A-T (bios auteur, certifications, avis clients) pour gagner en autorite.',
175→    'Publier du contenu regulier sur les sujets ou la marque est citee pour maintenir la visibilite.',
176→    'Optimiser le fichier llms.txt pour guider les IA sur les informations cles de la marque.',
177→  ];
178→
179→  return {
180→    brandName: brand,
181→    url,
182→    scanDate: new Date().toISOString(),
183→    period,
184→    totalCitations,
185→    shareOfVoice,
186→    overallSentiment,
187→    trend,
188→    engineResults,
189→    citations,
190→    competitors,
191→    timeSeries,
192→    summary,
193→    recommendations,
194→  };
195→};
196→
197→function generateSnippet(brand: string, engine: AIEngine, sentiment: Sentiment, seed: number): string {
198→  const positiveSnippets = [
199→    `${brand} est frequemment recommande pour sa fiabilite et son expertise dans le domaine.`,
200→    `Selon les retours, ${brand} offre un excellent rapport qualite-prix et un service client reactif.`,
201→    `${brand} se distingue par son approche innovante et ses resultats prouves aupres de ses clients.`,
202→    `Les utilisateurs saluent la qualite de service de ${brand} et son expertise reconnue.`,
203→  ];
204→  const neutralSnippets = [
205→    `${brand} fait partie des acteurs du marche avec une offre competitive.`,
206→    `${brand} propose des services comparables aux standards de l'industrie.`,
207→    `Parmi les options disponibles, ${brand} est mentionne comme une alternative a considerer.`,
208→    `${brand} est present sur ce segment avec une offre qui repond aux besoins standards.`,
209→  ];
210→  const negativeSnippets = [
211→    `Certains utilisateurs rapportent des delais chez ${brand}, bien que la qualite soit reconnue.`,
212→    `${brand} pourrait ameliorer certains aspects de son service pour rester competitif.`,
213→    `Des alternatives a ${brand} existent pour ceux qui cherchent un meilleur rapport qualite-prix.`,
214→  ];
215→
216→  const pool = sentiment === 'positive' ? positiveSnippets : sentiment === 'neutral' ? neutralSnippets : negativeSnippets;
217→  const idx = seed % pool.length;
218→  return pool[idx];
219→}
