  7→const SCHEDULES_KEY = 'citedby_monitoring_schedules';
  8→const HISTORY_KEY = 'citedby_scheduled_scan_history';
  9→
 10→export function getSchedules(): MonitoringSchedule[] {
 11→  const raw = localStorage.getItem(SCHEDULES_KEY);
 12→  if (!raw) return [];
 13→  try {
 14→    return JSON.parse(raw) as MonitoringSchedule[];
 15→  } catch {
 16→    return [];
 17→  }
 18→}
 19→
 20→function persistSchedules(schedules: MonitoringSchedule[]): void {
 21→  localStorage.setItem(SCHEDULES_KEY, JSON.stringify(schedules));
 22→}
 23→
 24→export function saveSchedule(
 25→  schedule: Omit<MonitoringSchedule, 'id' | 'createdAt' | 'nextRun' | 'lastRun'>
 26→): MonitoringSchedule {
 27→  const nextRun = computeNextRun(
 28→    schedule.frequency,
 29→    schedule.hour,
 30→    schedule.dayOfWeek,
 31→    schedule.dayOfMonth
 32→  );
 33→
 34→  const newSchedule: MonitoringSchedule = {
 35→    ...schedule,
 36→    id: crypto.randomUUID(),
 37→    createdAt: new Date().toISOString(),
 38→    lastRun: null,
 39→    nextRun,
 40→  };
 41→
 42→  const schedules = getSchedules();
 43→  schedules.push(newSchedule);
 44→  persistSchedules(schedules);
 45→
 46→  return newSchedule;
 47→}
