 49→export function deleteSchedule(id: string): void {
 50→  const schedules = getSchedules().filter((s) => s.id !== id);
 51→  persistSchedules(schedules);
 52→}
 53→
 54→export function togglePause(id: string): MonitoringSchedule | null {
 55→  const schedules = getSchedules();
 56→  const schedule = schedules.find((s) => s.id === id);
 57→  if (!schedule) return null;
 58→
 59→  schedule.paused = !schedule.paused;
 60→
 61→  if (!schedule.paused) {
 62→    schedule.nextRun = computeNextRun(
 63→      schedule.frequency,
 64→      schedule.hour,
 65→      schedule.dayOfWeek,
 66→      schedule.dayOfMonth
 67→    );
 68→  }
 69→
 70→  persistSchedules(schedules);
 71→  return schedule;
 72→}
 73→
 74→export function computeNextRun(
 75→  freq: ScheduleFrequency,
 76→  hour: string,
 77→  dayOfWeek?: number,
 78→  dayOfMonth?: number
 79→): string {
 80→  const [h, m] = hour.split(':').map(Number);
 81→  const now = new Date();
 82→  const next = new Date(now);
 83→
 84→  next.setHours(h, m, 0, 0);
 85→
 86→  if (freq === 'daily') {
 87→    if (next <= now) {
 88→      next.setDate(next.getDate() + 1);
 89→    }
 90→  } else if (freq === 'weekly' && dayOfWeek !== undefined) {
 91→    const currentDay = next.getDay();
 92→    let daysUntil = dayOfWeek - currentDay;
 93→    if (daysUntil < 0 || (daysUntil === 0 && next <= now)) {
 94→      daysUntil += 7;
 95→    }
 96→    next.setDate(next.getDate() + daysUntil);
 97→  } else if (freq === 'monthly' && dayOfMonth !== undefined) {
 98→    next.setDate(dayOfMonth);
 99→    if (next <= now) {
100→      next.setMonth(next.getMonth() + 1);
101→      next.setDate(dayOfMonth);
102→    }
103→  }
104→
105→  return next.toISOString();
106→}
