124→      disallow: ['/cart', '/orders', '/checkouts', '/account', '/collections/*+*', '/blogs/*+*', '/*design_theme_id'],
125→      sitemaps: ['/sitemap.xml', '/sitemap_products_1.xml']
126→    };
127→  }
128→
129→  if (lowerUrl.includes('wordpress') || lowerUrl.includes('blog') || lowerUrl.includes('wp-')) {
130→    return {
131→      name: 'WordPress',
132→      disallow: ['/wp-admin/', '/wp-includes/', '/wp-content/plugins/', '/xmlrpc.php', '/readme.html', '/?s='],
133→      sitemaps: ['/sitemap_index.xml', '/post-sitemap.xml']
