const errors = [];
const origError = console.error;
// Get any errors from the page
try {
  const logs = await new Promise((resolve) => {
    const entries = performance.getEntriesByType('resource').filter(e => e.name.includes('localhost'));
    resolve(entries.map(e => e.name));
  });
} catch(e) {}

// Check for visible error overlay
const overlay = document.querySelector('vite-error-overlay');
if (overlay) {
  return 'Vite error overlay found: ' + overlay.shadowRoot?.querySelector('.message-body')?.textContent;
}

// Check body content
return document.body.innerHTML.substring(0, 2000);

// Wait a bit for app to load
await new Promise(r => setTimeout(r, 3000));

// Check for vite error overlay
const overlay = document.querySelector('vite-error-overlay');
if (overlay) {
  const sr = overlay.shadowRoot;
  const msg = sr ? sr.querySelector('.message-body')?.textContent || sr.innerHTML.substring(0, 1000) : 'no shadow root';
  return 'VITE ERROR: ' + msg;
}

// Check body
const body = document.body.innerHTML;
if (body.length < 100) {
  return 'BODY IS NEARLY EMPTY: ' + body;
}
return 'BODY LENGTH: ' + body.length + ' | FIRST 500: ' + body.substring(0, 500);

